                new StatusUpdate("In Transit", "Chicago, IL", new DateTimeOffset(2026, 5, 24, 8, 15, 0, TimeSpan.Zero)),
            ]),
        ["TRK-002"] = new Shipment(
            "TRK-002",
            "Delivered",
            "San Francisco, CA",
            new DateTimeOffset(2026, 5, 20, 12, 0, 0, TimeSpan.Zero),
            [
                new StatusUpdate("Picked Up", "Seattle, WA", new DateTimeOffset(2026, 5, 18, 10, 0, 0, TimeSpan.Zero)),
                new StatusUpdate("In Transit", "Portland, OR", new DateTimeOffset(2026, 5, 19, 6, 45, 0, TimeSpan.Zero)),
                new StatusUpdate("Out for Delivery", "San Francisco, CA", new DateTimeOffset(2026, 5, 20, 8, 0, 0, TimeSpan.Zero)),
                new StatusUpdate("Delivered", "San Francisco, CA", new DateTimeOffset(2026, 5, 20, 11, 23, 0, TimeSpan.Zero)),
            ]),
        ["TRK-003"] = new Shipment(
            "TRK-003",
            "Out for Delivery",
            "Austin, TX",
            new DateTimeOffset(2026, 5, 25, 18, 0, 0, TimeSpan.Zero),
            [
                new StatusUpdate("Picked Up", "Dallas, TX", new DateTimeOffset(2026, 5, 24, 7, 0, 0, TimeSpan.Zero)),
                new StatusUpdate("In Transit", "Waco, TX", new DateTimeOffset(2026, 5, 24, 15, 20, 0, TimeSpan.Zero)),
                new StatusUpdate("Out for Delivery", "Austin, TX", new DateTimeOffset(2026, 5, 25, 9, 0, 0, TimeSpan.Zero)),
            ]),
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);
